// Guarda un dato en la memoria a largo plazo (Engram)
const axios = require('axios');
const response = await axios.post('http://host.docker.internal:7437/observations', {
  session_id: session_id,
  project: 'whatsapp-agent',
  scope: 'project',
  type: type,
  title: title,
  content: content,
  topic_key: topic_key
}, {
  headers: { 'Content-Type': 'application/json' }
});
return JSON.stringify(response.data);

